const INJECTION_HEADER_PREFIX = 'X-Inject-';
const CONTENT_HEADER_PREFIX = 'X-Content-';

exports.handler = async (event) => {
    const response = event.Records[0].cf.response;
    const request = event.Records[0].cf.request;
    
    const contentType = response.headers['content-type'] 
        ? response.headers['content-type'][0].value 
        : '';
    
    if (!contentType.includes('text/html')) {
        return response;
    }
    
    const injectionPoints = extractInjectionPoints(request.headers);
    
    if (Object.keys(injectionPoints).length === 0) {
        return response;
    }
    
    let body = '';
    if (response.body && response.body.data) {
        body = Buffer.from(response.body.data, response.body.encoding || 'base64').toString('utf8');
    }
    
    if (!body) {
        return response;
    }
    
    const modifiedBody = injectContent(body, injectionPoints);
    
    const encodedBody = Buffer.from(modifiedBody, 'utf8').toString('base64');
    
    response.body = {
        encoding: 'base64',
        data: encodedBody
    };
    
    const newContentLength = Buffer.byteLength(modifiedBody, 'utf8');
    response.headers['content-length'] = [{
        key: 'Content-Length',
        value: newContentLength.toString()
    }];
    
    removeInjectionHeaders(response.headers);
    
    return response;
};

function extractInjectionPoints(headers) {
    const injectionPoints = {};
    
    for (const headerName in headers) {
        const lowerHeaderName = headerName.toLowerCase();
        
        if (lowerHeaderName.startsWith(INJECTION_HEADER_PREFIX.toLowerCase())) {
            const pointName = lowerHeaderName.substring(INJECTION_HEADER_PREFIX.length);
            const selector = headers[headerName][0].value;
            
            const contentHeaderName = CONTENT_HEADER_PREFIX.toLowerCase() + pointName;
            
            if (headers[contentHeaderName]) {
                const content = decodeURIComponent(headers[contentHeaderName][0].value);
                
                injectionPoints[selector] = {
                    content: content,
                    pointName: pointName
                };
            }
        }
    }
    
    return injectionPoints;
}

function injectContent(html, injectionPoints) {
    let modifiedHtml = html;
    
    for (const selector in injectionPoints) {
        const { content } = injectionPoints[selector];
        
        if (selector.startsWith('id:')) {
            const id = selector.substring(3);
            modifiedHtml = injectById(modifiedHtml, id, content);
        } else if (selector.startsWith('class:')) {
            const className = selector.substring(6);
            modifiedHtml = injectByClass(modifiedHtml, className, content);
        } else if (selector.startsWith('tag:')) {
            const tagName = selector.substring(4);
            modifiedHtml = injectByTag(modifiedHtml, tagName, content);
        } else if (selector.startsWith('before:')) {
            const target = selector.substring(7);
            modifiedHtml = injectBefore(modifiedHtml, target, content);
        } else if (selector.startsWith('after:')) {
            const target = selector.substring(6);
            modifiedHtml = injectAfter(modifiedHtml, target, content);
        } else if (selector.startsWith('replace:')) {
            const target = selector.substring(8);
            modifiedHtml = replaceContent(modifiedHtml, target, content);
        } else if (selector === 'head-end') {
            modifiedHtml = injectBeforeClosingTag(modifiedHtml, 'head', content);
        } else if (selector === 'body-start') {
            modifiedHtml = injectAfterOpeningTag(modifiedHtml, 'body', content);
        } else if (selector === 'body-end') {
            modifiedHtml = injectBeforeClosingTag(modifiedHtml, 'body', content);
        } else {
            modifiedHtml = injectBySelector(modifiedHtml, selector, content);
        }
    }
    
    return modifiedHtml;
}

function injectById(html, id, content) {
    const regex = new RegExp(`(<[^>]+id=["']${escapeRegex(id)}["'][^>]*>)`, 'i');
    return html.replace(regex, `$1${content}`);
}

function injectByClass(html, className, content) {
    const regex = new RegExp(`(<[^>]+class=["'][^"']*\\b${escapeRegex(className)}\\b[^"']*["'][^>]*>)`, 'i');
    return html.replace(regex, `$1${content}`);
}

function injectByTag(html, tagName, content) {
    const regex = new RegExp(`(<${escapeRegex(tagName)}[^>]*>)`, 'i');
    return html.replace(regex, `$1${content}`);
}

function injectBefore(html, target, content) {
    const regex = new RegExp(`(${escapeRegex(target)})`, 'i');
    return html.replace(regex, `${content}$1`);
}

function injectAfter(html, target, content) {
    const regex = new RegExp(`(${escapeRegex(target)})`, 'i');
    return html.replace(regex, `$1${content}`);
}

function replaceContent(html, target, content) {
    const regex = new RegExp(escapeRegex(target), 'gi');
    return html.replace(regex, content);
}

function injectBeforeClosingTag(html, tagName, content) {
    const regex = new RegExp(`(</${escapeRegex(tagName)}>)`, 'i');
    return html.replace(regex, `${content}$1`);
}

function injectAfterOpeningTag(html, tagName, content) {
    const regex = new RegExp(`(<${escapeRegex(tagName)}[^>]*>)`, 'i');
    return html.replace(regex, `$1${content}`);
}

function injectBySelector(html, selector, content) {
    const idMatch = selector.match(/#([a-zA-Z0-9_-]+)/);
    if (idMatch) {
        return injectById(html, idMatch[1], content);
    }
    
    const classMatch = selector.match(/\.([a-zA-Z0-9_-]+)/);
    if (classMatch) {
        return injectByClass(html, classMatch[1], content);
    }
    
    const tagMatch = selector.match(/^([a-zA-Z0-9]+)$/);
    if (tagMatch) {
        return injectByTag(html, tagMatch[1], content);
    }
    
    return html;
}

function escapeRegex(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function removeInjectionHeaders(headers) {
    const headersToRemove = [];
    
    for (const headerName in headers) {
        const lowerHeaderName = headerName.toLowerCase();
        if (lowerHeaderName.startsWith(INJECTION_HEADER_PREFIX.toLowerCase()) ||
            lowerHeaderName.startsWith(CONTENT_HEADER_PREFIX.toLowerCase())) {
            headersToRemove.push(headerName);
        }
    }
    
    headersToRemove.forEach(headerName => {
        delete headers[headerName];
    });
}